INSERT INTO movies (title, release_year, phase, description, poster_url, watch_status, rating, duration_minutes) VALUES
('Iron Man', 2008, 1, 'Тони Старк — гениальный изобретатель и миллиардер — создаёт высокотехнологичный костюм-броню и становится супергероем Железным Человеком, чтобы защитить мир от зла.', 'https://image.tmdb.org/t/p/w500/78lPtwv72eTNqFW9COBYI0dWDJa.jpg', 'NOT_WATCHED', 7.9, 126),
('The Incredible Hulk', 2008, 1, 'Брюс Бэннер ищет лекарство от гамма-излучения, превратившего его в Халка, но вынужден противостоять новому чудовищу — Мерзости.', 'https://image.tmdb.org/t/p/w500/gKzYx79y0AQTL4UAk1cBQJ3nEsi.jpg', 'NOT_WATCHED', 6.7, 112),
('Iron Man 2', 2010, 1, 'Мир знает, что Тони Старк — Железный Человек. Под давлением правительства и нового врага Иван Ванко, Тони должен найти способ защитить всё, что ему дорого.', 'https://image.tmdb.org/t/p/w500/6WBeq4fCfn7AN0o21W9qNcRF2l9.jpg', 'NOT_WATCHED', 7.0, 124),
('Thor', 2011, 1, 'Могущественный, но высокомерный бог Тор изгнан на Землю, где учится смирению и должен доказать, что достоин своего молота Мьёльнира.', 'https://image.tmdb.org/t/p/w500/prSfAi1xGrhLQNxVSUFh61xQ4Qy.jpg', 'NOT_WATCHED', 7.0, 115),
('Captain America: The First Avenger', 2011, 1, 'Стив Роджерс, хрупкий юноша, становится суперсолдатом Капитаном Америкой и ведёт борьбу против нацистской организации ГИДРА во время Второй мировой войны.', 'https://image.tmdb.org/t/p/w500/vSNxAJTlD0r02V9sPYpOjqDZXUK.jpg', 'NOT_WATCHED', 6.9, 124),
('The Avengers', 2012, 1, 'Величайшие герои Земли — Железный Человек, Тор, Халк, Капитан Америка, Чёрная Вдова и Соколиный Глаз — объединяются, чтобы остановить вторжение Локи и армии читаури.', 'https://image.tmdb.org/t/p/w500/RYMX2wcKCBAr24UyPD7xwmjaTn.jpg', 'NOT_WATCHED', 8.0, 143),
('Iron Man 3', 2013, 2, 'Тони Старк сталкивается с могущественным врагом — Мандарином, который разрушает его мир. Без костюма и ресурсов, Тони должен рассчитывать только на себя.', 'https://image.tmdb.org/t/p/w500/qhPtAc1TKbMPqNvcdXSOn9Bn7hZ.jpg', 'NOT_WATCHED', 7.1, 130),
('Thor: The Dark World', 2013, 2, 'Тор должен спасти Девять Миров от Тёмных Эльфов, стремящихся погрузить вселенную во тьму с помощью древнего оружия — Эфира.', 'https://image.tmdb.org/t/p/w500/wp4SN0tDDAt1JimADeMX5XPmYiV.jpg', 'NOT_WATCHED', 6.9, 112),
('Captain America: The Winter Soldier', 2014, 2, 'Стив Роджерс адаптируется к современному миру и раскрывает заговор внутри Щ.И.Т., столкнувшись с загадочным убийцей — Зимним Солдатом.', 'https://image.tmdb.org/t/p/w500/tVFRpFw3xTedgPGqxW0AOv8b0N0.jpg', 'NOT_WATCHED', 7.7, 136),
('Guardians of the Galaxy', 2014, 2, 'Питер Квилл объединяется с группой космических изгоев — Гаморой, Драксом, Ракетой и Грутом — чтобы спасти галактику от фанатика Ронана.', 'https://image.tmdb.org/t/p/w500/r7vmZjiyZw9rpJMQJp0Oz7VnM5f.jpg', 'NOT_WATCHED', 8.0, 121),
('Avengers: Age of Ultron', 2015, 2, 'Мстители сталкиваются с Альтроном — искусственным интеллектом, созданным Тони Старком, который решает уничтожить человечество ради спасения Земли.', 'https://image.tmdb.org/t/p/w500/4ssDuvEDkSArWEdyBl2X5EHvYKU.jpg', 'NOT_WATCHED', 7.3, 141),
('Ant-Man', 2015, 2, 'Скотт Лэнг, бывший вор, получает костюм, позволяющий уменьшаться до размера муравья, и должен спасти мир от опасной технологии.', 'https://image.tmdb.org/t/p/w500/rQRnQfUl3kfp78nCWq8Ks04vnq1.jpg', 'NOT_WATCHED', 7.3, 117),
('Captain America: Civil War', 2016, 3, 'Мстители раскалываются на два лагеря: Капитан Америка противостоит Железному Человеку из-за Заковианского договора о контроле над супергероями.', 'https://image.tmdb.org/t/p/w500/rAGiXaUfPzY7CDEyNKUofk3Kw2e.jpg', 'NOT_WATCHED', 7.8, 147),
('Doctor Strange', 2016, 3, 'Нейрохирург Стивен Стрэндж после автокатастрофы открывает мир магии и мистических искусств, становясь Верховным Чародеем Земли.', 'https://image.tmdb.org/t/p/w500/uGBVj3bEbCoZbDjjl9wTxcygko1.jpg', 'NOT_WATCHED', 7.5, 115),
('Guardians of the Galaxy Vol. 2', 2017, 3, 'Стражи Галактики путешествуют по космосу, и Питер Квилл наконец встречает своего отца Эго — Живую Планету, скрывающего тёмные тайны.', 'https://image.tmdb.org/t/p/w500/y4MBh0EjBlMBezCX0xPNpcMpmMb.jpg', 'NOT_WATCHED', 7.6, 136),
('Spider-Man: Homecoming', 2017, 3, 'Питер Паркер балансирует между школьной жизнью и ролью Человека-Паука, стремясь доказать Тони Старку, что достоин стать Мстителем.', 'https://image.tmdb.org/t/p/w500/c24sv2weTHPsmDa7jEMN0m2P3RT.jpg', 'NOT_WATCHED', 7.4, 133),
('Thor: Ragnarok', 2017, 3, 'Тор оказывается на далёкой планете без молота и должен выиграть гладиаторский бой против Халка, чтобы вернуться в Асгард и остановить Хелу — богиню смерти.', 'https://image.tmdb.org/t/p/w500/rzRwTcFvttcN1ZpX2xv4j3tSdJu.jpg', 'NOT_WATCHED', 7.9, 130),
('Black Panther', 2018, 3, 'Т''Чалла возвращается в Ваканду, чтобы стать королём, но его право на трон оспаривает Эрик Киллмонгер, раскрывая тайны прошлого Ваканды.', 'https://image.tmdb.org/t/p/w500/uxzzxijgPIY7slzFvMotPv8wjKA.jpg', 'NOT_WATCHED', 7.3, 134),
('Avengers: Infinity War', 2018, 3, 'Мстители и их союзники объединяются для решающей битвы с Таносом, который собирает Камни Бесконечности, чтобы уничтожить половину вселенной.', 'https://image.tmdb.org/t/p/w500/7WsyChQLEftFiDhRkZUG1gqREkr.jpg', 'NOT_WATCHED', 8.4, 149),
('Ant-Man and the Wasp', 2018, 3, 'Скотт Лэнг сотрудничает с Хоуп ван Дайн и Хэнком Пимом в срочной миссии по спасению Джанет ван Дайн из Квантового мира.', 'https://image.tmdb.org/t/p/w500/rv1AWImgx386ULjcf62VYaW8zSt.jpg', 'NOT_WATCHED', 7.0, 118),
('Captain Marvel', 2019, 3, 'Кэрол Дэнверс становится одной из самых могущественных героев Вселенной, когда Земля оказывается в центре галактической войны между двумя инопланетными расами.', 'https://image.tmdb.org/t/p/w500/AtsgWhDnHTq68L0lLsUrCnM7TjG.jpg', 'NOT_WATCHED', 6.9, 123),
('Avengers: Endgame', 2019, 3, 'После опустошительного щелчка Таноса уцелевшие Мстители предпринимают последнюю отчаянную попытку отменить его действия и восстановить баланс во Вселенной.', 'https://image.tmdb.org/t/p/w500/or06FN3Dkh5RlUeyWXEAhbossS.jpg', 'NOT_WATCHED', 8.4, 181),
('Spider-Man: Far From Home', 2019, 3, 'Питер Паркер отправляется на школьную экскурсию в Европу, где сталкивается с новой угрозой — Элементалами и загадочным Мистерио.', 'https://image.tmdb.org/t/p/w500/4q2NNj4S5dG2RLF9CpXsej7yXl.jpg', 'NOT_WATCHED', 7.5, 129),
('Black Widow', 2021, 4, 'Наташа Романофф сталкивается с тёмными главами своего прошлого, когда возникает опасный заговор, связанный с её жизнью до Мстителей.', 'https://image.tmdb.org/t/p/w500/qAZ0pzat24kLdO3o8ejmbLxyOac.jpg', 'NOT_WATCHED', 6.7, 133),
('Shang-Chi and the Legend of the Ten Rings', 2021, 4, 'Шан-Чи должен противостоять прошлому, которое он считал оставленным, когда его втягивают в сеть тайной организации Десяти Колец.', 'https://image.tmdb.org/t/p/w500/1BIoJGKbXjdFDAqUEiA2VHqkK1Z.jpg', 'NOT_WATCHED', 7.4, 132),
('Eternals', 2021, 4, 'Вечные — древняя раса бессмертных существ — выходят из тени после тысячелетий, чтобы защитить Землю от своих злых двойников — Девиантов.', 'https://image.tmdb.org/t/p/w500/bcCBq9N1EMo3daNIjWJ8kYvrQm6.jpg', 'NOT_WATCHED', 6.3, 157),
('Spider-Man: No Way Home', 2021, 4, 'Когда личность Питера Паркера раскрыта, он просит Доктора Стрэнджа о помощи, но заклинание идёт не по плану, открывая мультивселенную.', 'https://image.tmdb.org/t/p/w500/1g0dhYtq4irTY1GPXvft6k4YLjm.jpg', 'NOT_WATCHED', 8.2, 148),
('Doctor Strange in the Multiverse of Madness', 2022, 4, 'Доктор Стрэндж путешествует по мультивселенной, чтобы защитить девочку-подростка Америку Чавес от Алой Ведьмы, жаждущей её силы.', 'https://image.tmdb.org/t/p/w500/9Gtg2DzBhmYamXBS1hKAhiwbBKS.jpg', 'NOT_WATCHED', 7.0, 126),
('Thor: Love and Thunder', 2022, 4, 'Тор отправляется в путешествие самопознания, но его покой прерывает Горр-Убийца Богов, стремящийся уничтожить всех богов.', 'https://image.tmdb.org/t/p/w500/pIkRyD18kl4FhoCNQuWxWu5cBLM.jpg', 'NOT_WATCHED', 6.3, 118),
('Black Panther: Wakanda Forever', 2022, 4, 'Народ Ваканды скорбит о потере короля Т''Чаллы и должен защитить свою страну от вторжения подводного королевства Талокан.', 'https://image.tmdb.org/t/p/w500/sv1xJUazXeYqALzczSZ3O6nkH75.jpg', 'NOT_WATCHED', 6.7, 161),
('Ant-Man and the Wasp: Quantumania', 2023, 5, 'Скотт Лэнг и его семья оказываются в Квантовом мире и сталкиваются с Кангом-Завоевателем — опаснейшим злодеем, угрожающим всей мультивселенной.', 'https://image.tmdb.org/t/p/w500/qnqGbB22YJ7dSs4o6M7exTpNxPz.jpg', 'NOT_WATCHED', 6.1, 125),
('Guardians of the Galaxy Vol. 3', 2023, 5, 'Стражи Галактики отправляются на миссию по спасению Ракеты, раскрывая его трагическое прошлое и сталкиваясь с Верховным Эволюционером.', 'https://image.tmdb.org/t/p/w500/r2J02Z2OpNTctfOSN1Ydgii51I3.jpg', 'NOT_WATCHED', 7.9, 150),
('The Marvels', 2023, 5, 'Кэрол Дэнверс, Камала Хан и Моника Рамбо объединяются, когда их силы переплетаются, и должны работать вместе, чтобы спасти вселенную.', 'https://image.tmdb.org/t/p/w500/9GBhzXMFjgcZ3FdR9w3bUMMi5rN.jpg', 'NOT_WATCHED', 6.1, 105),
('Deadpool & Wolverine', 2024, 5, 'Уэйд Уилсон (Дэдпул) вытаскивает Росомаху из отставки для совместной миссии по спасению мультивселенной от организации TVA.', 'https://image.tmdb.org/t/p/w500/8cdWjvZQUExUUTzyp4t6EDMubfO.jpg', 'NOT_WATCHED', 7.7, 128);
